1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type Result = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: Result[];
53	}
54	
55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	};
59	
60	const FIRST_INSURANCE_SURCHARGE = 1.1;
61	const PROCESSING_FEE = 5;
62	const FLOAT_PRECISION_DIGITS = 6;
63	
64	const quotePremium = (step: QuoteStep): number => {
65	  const itemTotal = step.items.reduce(
66	    (sum, item) => sum + BASE_PREMIUM[item.type] * FIRST_INSURANCE_SURCHARGE,
67	    0,
68	  );
69	  const premium = itemTotal + PROCESSING_FEE;
70	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
71	};
72	
73	export const runScenario = (scenario: Scenario): ScenarioResult => {
74	  return {
75	    results: scenario.steps.map((step) => ({
76	      premium: quotePremium(step as QuoteStep),
77	    })),
78	  };
79	};
